import{c as a,Q as d,j as e,m as r}from"./chunks/framework.BIBjCrbN.js";const c=JSON.parse('{"title":"神经科学方向（基础与临床）","description":"中国顶尖高校神经科学方向博士导师汇总，涵盖系统神经科学、分子神经科学、神经退行性疾病等方向","frontmatter":{"title":"神经科学方向（基础与临床）","description":"中国顶尖高校神经科学方向博士导师汇总，涵盖系统神经科学、分子神经科学、神经退行性疾病等方向"},"headers":[],"relativePath":"research-directions/neuroscience.md","filePath":"research-directions/neuroscience.md","lastUpdated":1780110618000}'),i={name:"research-directions/neuroscience.md"};function h(n,t,o,s,l,p){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="神经科学-基础与临床" tabindex="-1">神经科学（基础与临床） <a class="header-anchor" href="#神经科学-基础与临床" aria-label="Permalink to &quot;神经科学（基础与临床）&quot;">​</a></h1><h2 id="方向概述" tabindex="-1">方向概述 <a class="header-anchor" href="#方向概述" aria-label="Permalink to &quot;方向概述&quot;">​</a></h2><p>神经科学研究神经系统的结构、功能、发育和病理。国内此方向在<strong>北京大学</strong>（麦戈文研究所）、<strong>复旦大学</strong>（脑科学研究院）、<strong>中科院神经所</strong>（上海脑智卓越中心）拥有最强基础研究力量。</p><h2 id="子方向" tabindex="-1">子方向 <a class="header-anchor" href="#子方向" aria-label="Permalink to &quot;子方向&quot;">​</a></h2><ul><li><strong>系统神经科学</strong>：感觉/运动/认知神经回路 — 北大(方方)、中科院神经所、浙大</li><li><strong>细胞与分子神经科学</strong>：神经递质、突触传递 — 北大(李毓龙)</li><li><strong>神经发育与可塑性</strong>：轴突导向、神经再生 — 中科院神经所(蒲慕明)</li><li><strong>神经退行性疾病</strong>：AD/PD模型 — 清华、复旦、浙大</li><li><strong>计算神经科学</strong>：神经信息编码、神经网络模型 — 北大(吴思)、浙大(江海腾)</li><li><strong>认知神经科学</strong>：注意/记忆/语言 — 北大(方方、纳家勇治)</li></ul><hr><h2 id="导师全索引" tabindex="-1">导师全索引 <a class="header-anchor" href="#导师全索引" aria-label="Permalink to &quot;导师全索引&quot;">​</a></h2><h3 id="北京大学" tabindex="-1">北京大学 <a class="header-anchor" href="#北京大学" aria-label="Permalink to &quot;北京大学&quot;">​</a></h3><table tabindex="0"><thead><tr><th>导师</th><th>职称</th><th>所在学院</th><th>核心方向</th></tr></thead><tbody><tr><td><a href="/apply-phd/universities/peking#方方-教授-博导">方方</a></td><td>教授</td><td>心理与认知科学学院</td><td>视觉认知神经科学、fMRI/EEG</td></tr><tr><td><a href="/apply-phd/universities/peking#吴思-教授-博导">吴思</a></td><td>教授</td><td>心理与认知科学学院</td><td>计算神经科学、神经信息编码</td></tr><tr><td><a href="/apply-phd/universities/peking#纳家勇治-研究员-博导">纳家勇治</a></td><td>研究员</td><td>心理与认知科学学院</td><td>记忆神经科学（2026年招生中）</td></tr><tr><td><a href="/apply-phd/universities/peking#李毓龙-教授-博导">李毓龙</a></td><td>教授</td><td>生命科学学院</td><td>神经递质探针(GRAB)、分子神经科学</td></tr></tbody></table><p>详见 <a href="/apply-phd/universities/peking">北京大学</a> 页面。</p><h3 id="中国科学院脑智卓越中心-神经所-上海" tabindex="-1">中国科学院脑智卓越中心（神经所，上海） <a class="header-anchor" href="#中国科学院脑智卓越中心-神经所-上海" aria-label="Permalink to &quot;中国科学院脑智卓越中心（神经所，上海）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>导师</th><th>职称</th><th>核心方向</th></tr></thead><tbody><tr><td>蒲慕明</td><td>院士</td><td>神经可塑性、轴突导向</td></tr><tr><td>杜久林</td><td>研究员</td><td>斑马鱼神经发育与行为</td></tr><tr><td>多位PI</td><td>—</td><td>视觉、运动、学习记忆等</td></tr></tbody></table><p>详见 <a href="/apply-phd/universities/cas">中国科学院</a> 页面。</p><h3 id="复旦大学" tabindex="-1">复旦大学 <a class="header-anchor" href="#复旦大学" aria-label="Permalink to &quot;复旦大学&quot;">​</a></h3><table tabindex="0"><thead><tr><th>导师</th><th>职称</th><th>所在学院</th><th>核心方向</th></tr></thead><tbody><tr><td><a href="/apply-phd/universities/fudan#纪鹏-研究员-博导">纪鹏</a></td><td>研究员</td><td>类脑智能研究院</td><td>计算神经科学、神经元网络建模 — 🟢2026有名额</td></tr><tr><td><a href="/apply-phd/universities/fudan#尤佳-青年研究员-博导">尤佳</a></td><td>青年研究员</td><td>类脑智能研究院</td><td>AD智能诊断、多组学数据分析</td></tr><tr><td><a href="/apply-phd/universities/fudan#彭勃-教授-二级-博导">彭勃</a></td><td>教授(二级)</td><td>脑科学转化研究院</td><td>小胶质细胞替换疗法、神经退行性疾病</td></tr><tr><td><a href="/apply-phd/universities/fudan#魏依娜-研究员-博导">魏依娜</a></td><td>研究员</td><td>脑智研究院</td><td>计算神经科学、脑机接口、睡眠与记忆</td></tr><tr><td><a href="/apply-phd/universities/fudan#刘裕峰-研究员-博导">刘裕峰</a></td><td>研究员</td><td>脑智研究院</td><td>AI+神经影像、类脑网络</td></tr><tr><td>Gunter Schumann</td><td>特聘教授(院士)</td><td>类脑智能研究院</td><td>多模态神经影像、计算精神病学</td></tr></tbody></table><p>详见 <a href="/apply-phd/universities/fudan">复旦大学</a> 页面。</p><h3 id="东南大学" tabindex="-1">东南大学 <a class="header-anchor" href="#东南大学" aria-label="Permalink to &quot;东南大学&quot;">​</a></h3><table tabindex="0"><thead><tr><th>导师</th><th>职称</th><th>所在学院</th><th>核心方向</th></tr></thead><tbody><tr><td><a href="/apply-phd/universities/seu#顾忠泽-首席教授-博导">顾忠泽</a></td><td>首席教授、长江学者</td><td>BME学院/器官芯片研究院</td><td>类脑器官混合智能、电生理信号采集</td></tr></tbody></table><blockquote><p>顾忠泽团队的&quot;基于人工类脑器官的混合智能&quot;方向涉及类脑器官培养+电生理+智能机器人，与你的背景高度吻合。</p></blockquote><h3 id="浙江大学" tabindex="-1">浙江大学 <a class="header-anchor" href="#浙江大学" aria-label="Permalink to &quot;浙江大学&quot;">​</a></h3><p>除BCI方向外，浙大医学院在神经科学基础研究方面也有布局。 详见 <a href="/apply-phd/universities/zju">浙江大学</a> 页面。</p><hr><h2 id="针对你的申请建议" tabindex="-1">针对你的申请建议 <a class="header-anchor" href="#针对你的申请建议" aria-label="Permalink to &quot;针对你的申请建议&quot;">​</a></h2><p>神经科学方向与你的背景匹配度分析：</p><ul><li><strong>计算神经科学</strong>：⭐⭐⭐⭐ — 数学/编程能力强是优势，与你的MATLAB/Python背景匹配</li><li><strong>神经退行性疾病模型</strong>：⭐⭐⭐⭐ — 脑类器官(AD模型)经验直接对口</li><li><strong>系统神经科学</strong>：⭐⭐⭐ — 需补充更多体内电生理实验经验</li><li><strong>分子神经科学</strong>：⭐⭐ — 需要更多分子生物学和生化实验技能</li></ul><p>建议策略：以你的iPSC/脑类器官研究经验为切入点，申请偏向<strong>神经退行性疾病模型</strong>或<strong>类器官技术平台</strong>方向的课题组。北京大学李毓龙（神经递质探针）和复旦大学的脑类器官相关课题组值得重点关注。</p>',26)])])}const b=a(i,[["render",h]]);export{c as __pageData,b as default};
